patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -1,7 +1,7 @@
 module mux_4to1(
   input [7:0] in0, in1, in2, in3,
   input [1:0] sel,
   output [7:0] out
 );
-  always @(in0 or in1) begin
+  always @(in0 or in1 or in2 or in3 or sel) begin
     case(sel)
       2'b00: out = in0;
       2'b01: out = in1;

before_code:
module mux_4to1(
  input [7:0] in0, in1, in2, in3,
  input [1:0] sel,
  output [7:0] out
 );
  always @(in0 or in1) begin
    case(sel)
      2'b00: out = in0;
      2'b01: out = in1;
      2'b10: out = in2;
      2'b11: out = in3;
    endcase
  end
endmodule

after_code:
module mux_4to1(
  input [7:0] in0, in1, in2, in3,
  input [1:0] sel,
  output [7:0] out
 );
  always @(in0 or in1 or in2 or in3 or sel) begin
    case(sel)
      2'b00: out = in0;
      2'b01: out = in1;
      2'b10: out = in2;
      2'b11: out = in3;
    endcase
  end
endmodule
